public partial class PreClientesService
{
    /// <summary>
    /// Processa comando de voz para gerar filtro via OpenAI usando serviço genérico
    /// </summary>
    /// <param name = "message">Requisição com comando de voz</param>
    /// <param name = "existingFilter">Filtro existente para combinar</param>
    /// <param name = "uri">URI da base de dados</param>
    /// <returns>FilterPreClientes processado</returns>
    private async Task<Filters.FilterPreClientes?> ProcessFilterVoiceCommandAsync(CommandSpeakerRequest message, Filters.FilterPreClientes? existingFilter, string uri)
    {
        try
        {
            // Usar o contexto do FilterPreClientesTXT
            var context = FilterPreClientesTXT.GetPrompt(existingFilter, FilterPreClientesTXT.GetOptions());
            // Instruções específicas para PreClientes
            var additionalInstructions = "";
            // Processar com o serviço genérico
            var filtroProcessado = await _voiceFilterService.ProcessVoiceCommandWithFallbackAsync(message.Message, context, existingFilter, additionalInstructions, uri);
            return filtroProcessado;
        }
        catch (Exception)
        {
            // Se falhar, retornar filtro existente ou novo
            return existingFilter ?? new Filters.FilterPreClientes();
        }
    }

    private async Task<IEnumerable<PreClientesResponseAll>> GetDataAllAsync(int max, string where, List<SqlParameter>? parameters, string uri, CancellationToken cancellationToken)
    {
        using var scope = _connectionService.CreateConnectionScope(uri);
        using var oCnn = scope.Connection;
        if (oCnn == null)
        {
            return[];
        }

        try
        {
            // Usar o reader para obter os dados
            return await reader.ListarAsync(max, uri, where.Replace(TSql.Where, ""), parameters, "", cancellationToken);
        }
        catch (Exception)
        {
            return[];
        }
    }

    public async Task<IEnumerable<NomeID>> GetListN([FromQuery] int max, [FromBody] Filters.FilterPreClientes? filtro, [FromRoute, Required] string uri, CancellationToken token)
    {
        // Tracking: 20250606-0
        ThrowIfDisposed();
        if (!(await Uris.ValidaUriAsync(uri, _entityService)))
        {
            throw new Exception("PreClientes: URI inválida");
        }

        var filtroResult = filtro == null ? null : servicesFilter.WFiltroPreClientes(filtro!);
        string where = filtroResult?.where ?? string.Empty;
        List<SqlParameter>? parameters = filtroResult?.parametros ?? [];
        using var scope = _connectionService.CreateConnectionScope(uri);
        using var oCnn = scope.Connection;
        if (oCnn == null)
        {
            throw new Exception($"Coneão nula.");
        }

        var keyCache = await reader.ReadStringAuditorAsync(max, uri, "", [], oCnn);
        var cacheKey = $"{uri}-PreClientes-{max}-{where.GetHashCode()}-GetListN-{keyCache}";
        var entryOptions = new HybridCacheEntryOptions
        {
            Expiration = TimeSpan.FromSeconds(BaseConsts.PMaxSecondsCacheId),
            LocalCacheExpiration = TimeSpan.FromSeconds(BaseConsts.PMaxSecondsCacheId)
        };
        return await _cache.GetOrCreateAsync(cacheKey, async cancel => await GetDataListNAsync(max, uri, where, parameters, cancel), entryOptions, cancellationToken: token) ?? [];
    }

    private async Task<IEnumerable<NomeID>> GetDataListNAsync(int max, string uri, string where, List<SqlParameter>? parameters, CancellationToken token)
    {
        var result = new List<NomeID>(max);
        var lista = await reader.ListarNAsync(max, uri, where, parameters, DBPreClientesDicInfo.CampoNome);
        if (lista == null || !lista.Any())
        {
            return result;
        }

        foreach (var item in lista)
        {
            if (token.IsCancellationRequested)
                continue;
            if (item?.FNome != null)
            {
                result.Add(new NomeID { Nome = item.FNome, ID = item.ID });
            }
        }

        return result;
    }

    public async Task<IEnumerable<PreClientesResponseAll>> GetAll(int max, [FromRoute, Required] string uri, CancellationToken token = default)
    {
        ThrowIfDisposed();
        max = Math.Min(Math.Max(max, 1), BaseConsts.PMaxItens);
        if (!(await Uris.ValidaUriAsync(uri, _entityService)))
        {
            throw new Exception("PreClientes: URI inválida");
        }

        var entryOptions = new HybridCacheEntryOptions
        {
            Expiration = TimeSpan.FromMinutes(BaseConsts.PMaxMinutesCache),
            LocalCacheExpiration = TimeSpan.FromMinutes(BaseConsts.PMaxMinutesCache)
        };
        using var scope = _connectionService.CreateConnectionScope(uri);
        using var oCnn = scope.Connection;
        var keyCache = await reader.ReadStringAuditorAsync(max, uri, "", [], oCnn);
        var cacheKey = $"{uri}-PreClientes-Filter-{max}-{keyCache}";
        var result = await _cache.GetOrCreateAsync(cacheKey, async cancel => await GetDataAllAsync2(max, string.Empty, [], uri, cancel), entryOptions, cancellationToken: token);
        return result;
    }

    private async Task<IEnumerable<PreClientesResponseAll>> GetDataAllAsync2(int max, string where, List<SqlParameter>? parameters, string uri, CancellationToken token)
    {
        using var scope = _connectionService.CreateConnectionScope(uri);
        using var oCnn = scope.Connection;
        if (oCnn == null)
        {
            throw new DatabaseConnectionException();
        }

        var result = await reader.ListarAsync(max, uri, where, parameters, string.Empty, token);
        return result;
    }
